def print_chessboard(n): # nakreslí ASCII šachovnici o n délce a šířce
    if n % 2 == 0:
        for i in range(n//2):
            print((n//2) * ("# " + ". "))
            print((n//2) * (". " + "# "))
    elif n % 2 == 1:
        for j in range(n//2):
            print((n//2) * ("# " + ". ") + "#")
            print((n//2) * (". " + "# ") + ".")
        print((n//2) * ("# " + ". ") + "#")

