def get_most_common_value(mylist):
    count_elements = 0
    for element in mylist:
        common = mylist.count(element)
        if common >= count_elements:
            most_common_numbers = []
            most_common_numbers.append(element)
            count_elements = common
    return min(most_common_numbers)

def get_most_common_value(mylist):
    count_r = 0
    result = 0
    most_common = 0
    list_of_most_common = []
    for i in range(len(mylist)):
        count_r = mylist.count(mylist[i])
        if count_r == result:
            list_of_most_common.append(mylist[i])
        if count_r > result:
            result = count_r
            most_common = mylist[i]
    if len(list_of_most_common) > 1:
        return min(list_of_most_common)
    return most_common

def get_most_common_value(mylist):
    counts = {}
    for i in mylist:
        cnt = mylist.count(i) 
        counts[i] = cnt
    #print(counts)
    cnts = []
    for i in range(max(counts)+1):
        if i in counts:
            cnt = counts.get(i)
            #print(i,cnt)
            cnts.append((i,cnt))
    cnts.sort(key=lambda x: x[1])
    #print(cnts)    
    same = []
    mx = cnts[-1][1]
    for i in range(len(cnts)-1,-1,-1):
        if cnts[i][1] == mx:
            same.append(cnts[i][0])
    return min(same)

