from collections import OrderedDict

def print_letter_frequencies(text):
    f = OrderedDict()
    for letter in text:
        if not letter in f:
            f[letter] = 1
        else:
            count = f[letter]
            f[letter] = count + 1
    for key, value in f.items():
        print(key, value)

