def zip_strings(text1, text2):
    zip1_celkem=""
    zip2_celkem=""
    minimalni_delka=min(len(text1),len(text2))
    for i in range(minimalni_delka):
        zip1 = text1[i]+text2[i]
        zip1_celkem += zip1
    if len(text1) == minimalni_delka:
        for j in range(minimalni_delka,len(text2)):
            zip2 = text2[j]
            zip2_celkem += zip2
    else:
        for j in range(minimalni_delka,len(text1)):
            zip2 = text1[j]
            zip2_celkem += zip2
    zip = zip1_celkem + zip2_celkem
    return zip

