def not_prime(rest):
    for i in range(2,rest):
        if rest%i==0:
            return True

    return False


def step(num):
    for i in range(2,num):
        if (num%i)==0:
            return i,int(num/i)




def factorize(n):
    primes = []
    rest = n
    prime = 0
    while rest<=n:

        if not_prime(rest):
            prime,rest = step(rest)
            primes.append(prime)
        else:
            primes.append(rest)
            break
    print(n,"="," * ".join(map(str,primes)))

def myFunc(e):
    return len(e)

def line(w):
    alist = list(w)
    alist.sort(reverse=True, key = myFunc )
    k = len(alist[0])
    for i in range(k+2):
        print("+", end='')
    print()

def print_big_frame(w):
    alist = list(w)
    alist.sort(reverse=True, key = myFunc )
    k = len(alist[0])
    line(w)
    for i in w:
        print("+"+i, end="")
        print(" "*(k-len(i)), end="")
        print("+")
    line(w)

def print_nested_squares(n):
    def make_upper_square(list, char):
        length = len(list)
        for i in range(length):
            list[i] = char + list[i] + char
        list.append(char * (length + 2))
        list.insert(0, char * (length + 2))

    matrix = [ '#' ]

    for i in range(n - 1):
        make_upper_square(matrix, ' ')
        make_upper_square(matrix, '#')

    for line in matrix:
        print(line)

def print_arrow(n):
    change = n
    reverse = n-2
    for i in range(n):
        for j in range(n):
            if i < n//2:
                c = '.'
                if j==change//2:      # zde opravit
                    c = '*'
                print(c, end="")
            elif i==n//2:
                print("*",end="")
            else:
                c = '.'
                if j==reverse:
                    c = "*"
                print(c,end="")
        if i > n//2:
            reverse-=1
        change+=2
        print()

