def print_letter_frequencies(text):
    # inicializace slovníku pro počítání výskytů
    count = {}

    # projití celého řetězce a naplnění slovníku
    for char in text:
        if char not in count:
            count[char] = 0 
        count[char] += 1

    # vypsání počtu výskytů jednotlivých znaků v pořadí jako v textu
    for char in text:
        if char in count:
            print(char + " " + str(count[char]))
            del count[char]

