def get_training_time(activities, lengths):
    lenght_total = 0
    for a in activities:
        if a in lengths:
            lenght_total += lengths[a]
    return lenght_total

def check(transactions):
    buffer=[]
    chyba = 0
    transactions = transactions.split()    
    for index, obchod in enumerate(transactions):
        if obchod.count("+"):
            buffer += obchod[1]
        elif obchod.count("-"):
            if buffer.count(obchod[1]) == 0:
                print("Chyba:",obchod[1])
                chyba +=1
                break 
            elif buffer.count(obchod[1]) == 1:
                buffer.remove(obchod[1])
    if chyba == 0:
        print("OK")
